	"fmt"
	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/metric"
	"github.com/openmeterio/openmeter/pkg/kafka/metrics/stats"
)

// 1. Add field to struct:
type BrokerMetrics struct {
	// ... existing fields ...
	NewGauge metric.Int64Gauge
}

// 2. Register in NewBrokerMetrics (after other core gauges):
m.NewGauge, err = meter.Int64Gauge(
	"kafka.broker.new_gauge",
	metric.WithDescription("Description of the new gauge"),
	metric.WithUnit("{unit}"),
)
if err != nil {
	return nil, fmt.Errorf("failed to create metric: kafka.broker.new_gauge: %w", err)
}

// 3. Record in Add (after attrs are appended):
m.NewGauge.Record(ctx, stats.NewField, metric.WithAttributes(attrs...))

