// In stats/broker.go (or appropriate file):
const (
	MyEnumUnknown MyEnum = "unknown"
	MyEnumFoo     MyEnum = "foo"
	MyEnumBar     MyEnum = "bar"
)

type MyEnum string

func (s *MyEnum) UnmarshalJSON(data []byte) error {
	var value string
	if err := json.Unmarshal(data, &value); err != nil {
		return fmt.Errorf("failed to unmarshal value: %s", data)
	}
	switch strings.ToLower(strings.TrimSpace(value)) {
	case "foo":
		*s = MyEnumFoo
	case "bar":
		*s = MyEnumBar
	default:
		*s = MyEnumUnknown
	}
	return nil
}

func (s MyEnum) Int64() int64 {
	switch s {
	case MyEnumFoo:
		return 0
	case MyEnumBar:
		return 1
	default:
		return -1 // Unknown must be -1, never 0
	}
}

// Add to struct with exact librdkafka json tag:
type BrokerStats struct {
	MyField MyEnum `json:"my_librdkafka_field_name"`
}
